public class FilterDialog extends Dialog { private static final String DIALOG_TITLE = Messages . getString ( "FilterDialog.FilterEditor" ) ; private static final int FORMAT_BUTTON_ID = 987654321 ; private String title ; private IBrowserConnection browserConnection ; private SourceViewer sourceViewer ; private FilterSourceViewerConfiguration configuration ; private LdapFilterParser parser ; private String filter ; public FilterDialog ( Shell parentShell , String title , String filter , IBrowserConnection brwoserConnection ) { super ( parentShell ) ; this . title = title ; this . filter = filter ; this . browserConnection = brwoserConnection ; this . parser = new LdapFilterParser ( ) ; setShellStyle ( SWT . DIALOG_TRIM | SWT . APPLICATION_MODAL | SWT . RESIZE ) ; } public String getFilter ( ) { return filter ; } protected void configureShell ( Shell newShell ) { super . configureShell ( newShell ) ; newShell . setText ( title != null ? title : DIALOG_TITLE ) ; newShell . setImage ( BrowserCommonActivator . getDefault ( ) . getImage ( BrowserCommonConstants . IMG_FILTER_EDITOR ) ) ; } protected void buttonPressed ( int buttonId ) { if ( buttonId == IDialogConstants . OK_ID ) { parser . parse ( sourceViewer . getDocument ( ) . get ( ) ) ; filter = parser . getModel ( ) . toString ( ) ; } else if ( buttonId == FORMAT_BUTTON_ID ) { IRegion region = new Region ( 0 , sourceViewer . getDocument ( ) . getLength ( ) ) ; configuration . getContentFormatter ( sourceViewer ) . format ( sourceViewer . getDocument ( ) , region ) ; } super . buttonPressed ( buttonId ) ; } protected Control createButtonBar ( Composite parent ) { Composite composite = ( Composite ) super . createButtonBar ( parent ) ; super . createButton ( composite , FORMAT_BUTTON_ID , Messages . getString ( "FilterDialog.Format" ) , false ) ; return composite ; } protected Control createDialogArea ( Composite parent ) { Composite composite = ( Composite ) super . createDialogArea ( parent ) ; GridData gd = new GridData ( GridData . FILL_BOTH ) ; gd . widthHint = convertHorizontalDLUsToPixels ( IDialogConstants . MINIMUM_MESSAGE_AREA_WIDTH ) ; gd . heightHint = convertHorizontalDLUsToPixels ( IDialogConstants . MINIMUM_MESSAGE_AREA_WIDTH ) ; composite . setLayoutData ( gd ) ; sourceViewer = new SourceViewer ( composite , new VerticalRuler ( 0 ) , SWT . H_SCROLL | SWT . V_SCROLL ) ; sourceViewer . getControl ( ) . setLayoutData ( new GridData ( GridData . FILL_BOTH ) ) ; configuration = new FilterSourceViewerConfiguration ( parser , browserConnection ) ; sourceViewer . configure ( configuration ) ; IDocument document = new Document ( filter ) ; sourceViewer . setDocument ( document ) ; IRegion region = new Region ( 0 , sourceViewer . getDocument ( ) . getLength ( ) ) ; configuration . getContentFormatter ( sourceViewer ) . format ( sourceViewer . getDocument ( ) , region ) ; sourceViewer . getTextWidget ( ) . setFocus ( ) ; return composite ; } }